section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-flake-ledger-template.json",
  "type": "object",
  "title": "QA Flake Ledger Template",
  "required": [
    "ledger_version",
    "entries",
    "review_cadence_days",
    "quarantine_threshold_fail_rate",
    "quarantine_threshold_run_count",
    "source_ci"
  ],
  "additionalProperties": false,
  "properties": {
    "ledger_version": {
      "type": "string",
      "minLength": 1,
      "description": "Semver of the ledger schema."
    },
    "entries": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {test_id, owner, first_seen, last_seen, run_count, fail_count, root_cause, state}."
    },
    "review_cadence_days": {
      "type": "integer",
      "description": "Days between reviews; \u226414."
    },
    "quarantine_threshold_fail_rate": {
      "type": "number",
      "description": "Fail rate that auto-quarantines; e.g. 0.05."
    },
    "quarantine_threshold_run_count": {
      "type": "integer",
      "description": "Min runs in window; e.g. 10."
    },
    "source_ci": {
      "type": "string",
      "minLength": 1,
      "description": "CI provider name."
    }
  }
}
